// Verify /api/directions returns 400 when lat/lon are missing
async function testDirectionsMissingParams() {
  const res = await fetch('http://localhost:3001/api/directions');
  assertEquals(res.status, 400);
  const body = await res.json();
  assertEquals(body.error, true);
  assertEquals(body.message, 'lat and lon query parameters are required');
}
